(64, 63, 'having_trouble_logging_in', 'Having trouble logging in?', 'Having trouble logging in?', 'Having trouble logging in?', 'Having trouble logging in?', '', '1', '7', NULL, NULL, NULL, '', NULL, '<form method="post">\r\n                        Having trouble logging in?<br /><br />Please contact us at carguide<a href="mailto:info@mtp.ie">@mtp.ie</a>&nbsp;with your name and company name and the nature of your issue ie: Forgotten password, link not working etc<br /></form>', NULL, 5, 1, 1, '', 1),
(42, 3, 'mobile_app', 'Mobile app', 'Mobile app', 'Mobile app', 'Mobile app', 'Vehicle, value, cost, ireland, cars, audi, bmw, fiat, ford, honda, hyundai, toyota, volkswagen, mercedes, renault, opel, nissan, peugeot, car, cars, sell, buy, new, used, car sales, sell car, sell my car, buying cars, importing cars, VRT, app, iphone app, used car sales\r\nused values\r\ncar values\r\nused cars dublin\r\ncar prices\r\nBMW parts\r\nnew cars\r\nnew cars dublin\r\nnew car deals\r\nnew cars ireland\r\nused car dealerships dublin\r\nsell your car\r\n10 day car sales\r\n10 day SIMI figures\r\n20 day SIMI\r\n30 day SIMI\r\ncar price\r\neditorial\r\ncar news\r\nbuy a car\r\nsell a car\r\nselling my car\r\nhow much is my car\r\ncar ireland\r\ncar valuation ireland\r\ntrade in value of car\r\ncar trade in value\r\ncar value ireland calculator', '1', '40', NULL, NULL, NULL, '', '21', '<span style="font-family:helvetica, sans-serif"><h1 style="text-align:left;font-size:x-large;color:#339999">Accurate used values at your fingertips….anywhere, anytime.</h1><div style="text-align:justify"><div style="text-align:left">Whether it’s from behind the desk, in a sales meeting, with a customer or simply to satisfy curiosity, theCarGuide app for iPhone allows subscribers to access our accurate data anywhere and anytime – <span style="font-weight: bold; font-size: large; color: rgb(51, 153, 153); " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media770584300160408" width="150" height="100">FOR FREE.</span></div><br /><br /><span style="font-weight: bold; color: rgb(51, 153, 153); " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media6004849658347666" width="150" height="100">Easy to use</span> – simple scroll and select functions. Makes and models are listed as they appear on distributor price lists so you don’t have to waste time inserting each vehicles individual detail.<br /><br /><span style="font-weight: bold; color: rgb(51, 153, 153); " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media6222505075857043" width="150" height="100">Kilometre adjustment calculator </span>– select the relevant year and change the odometer reading to suit your particular model. Let our sophisticated kms adjustment algorithm return you an even more accurate value.<br /><br /><span style="font-weight: bold; color: rgb(51, 153, 153); " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media07772097317501903" width="150" height="100">Additional Notes</span> – Our “info” icon at the top of the screen provides you with the technical details of your selected vehicle. Find out it’s CO2 value, engine cc, when the model was introduced or received a mid-model face lift as well as optional extras available and their price when new.<br /><br /><span style="font-weight: bold; color: rgb(51, 153, 153); " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media09205798688344657" width="150" height="100">Time saving</span> - Get the values that matter instantly without wasting time browsing pages of similar vehicles for sale and having to eliminate private sale values, asking prices or different body shapes.&nbsp;</div><div style="text-align:justify"><br /><span style="font-weight:bold;font-size:large;color:#339999" class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media30723716551437974" width="150" height="100">Simply scroll, select and sell</span><span style="color:#339999">.</span></div></span>', NULL, 2, 1, 1, 'Mobile app', 1),
(59, 3, 'services', 'Services', 'Services', 'Services', 'Services', '', '4', '40', NULL, NULL, NULL, 'http://www.mtp.ie/index.php?r=cms/cmsPage/displayPage&url=products', '96', '<div style="text-align:justify"><br /><span style="font-size:x-large;color:#339999">Motor dealers</span>&nbsp;can access our information via the following&nbsp;mediums.&nbsp;</div><div><span style="font-weight:bold;color:#3399ff"><br /></span></div><div><span style="font-weight:bold;font-size:large;color:#339999">A</span> the members area of this website</div><div><div><span style="font-weight:bold;font-size:large;color:#339999">B</span>&nbsp;our free&nbsp;iPhone app</div></div><div><span style="font-weight: bold; font-size: large; color: rgb(51, 153, 153); " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media1304103215225041" width="150" height="100">C</span> <span style="font-size:medium">o</span>ur long standing publications&nbsp;</div><div><span style="font-weight: bold; font-size: large; color: rgb(51, 153, 153); " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media7653512335382402" width="150" height="100">D&nbsp;</span>our computer software</div><div><br /></div><div style="text-align:justify"> The software can be downloaded and instantly activated and our archived files can be used as refe<span style="font-size:medium">rence fo</span>r tracking a vehicle''s performance throughout the year. (sample screenshot of software)</div><div></div><div style="text-align:justify"><br /><span style="font-size:x-large;color:#339999">Insurance &amp; Finance Companies</span>&nbsp;should note that we provide a comprehensive solution to valuing vehicles for the purposes of underwriting and for the swift resolution of claims. The following video highlights how our values can be easily integrated into any existing system.&nbsp;</div><div><br /></div><div><iframe src="http://www.youtube.com/embed/qyg9t7RjOfM" frameborder="0" height="360" width="480"></iframe></div><span style="color:#339999;font-size:large;font-weight:bold"><br /></span><span style="color:#339999;font-size:x-large">Industry Reports</span> Our extensive research and analysis of the market ensures that we capture an unrivalled insight into the performance of the industry. This allows us to produce timely reports on a number of key market trends as well as shifts in consumer attitude and any other extraneous circumstances with a direct or indirect impact on the motor trade.  <br /><br /><div><span style="color: rgb(102, 102, 102); font-size: x-large; " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="http://qbix-soft.pl/mtp/assets/b406734b/images/pixel.gif" rel="media06931364862248302" width="150" height="100">&nbsp;</span><span style="color: rgb(102, 102, 102); font-size: x-large; " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="http://qbix-soft.pl/mtp/assets/b406734b/images/pixel.gif" rel="media5094425426796079" width="150" height="100"><iframe src="http://www.youtube.com/embed/aPQv5gxy5xo" frameborder="0" height="360" width="480"></iframe><br /></span></div><br /><span style="font-size:x-large;color:#339999">Expertise</span> Our prominence in the industry has attracted attention from radio programs such as TodayFM’s The Last Word with Matt Cooper and Q102’s The Scott Williams Show as well as having produced informative statistical analysis for use in newspaper articles. We also hope that our 13 page proposal for the restructuring of the motor tax system will form a critical role in the government’s overhaul of the framework for 2013. We appeared on Ireland AM to voice our standpoint on this in March 2012.&nbsp;<div><br /></div><div style="font-family:helvetica, sans-serif">The link to this interview can be found here:</div><div><br /></div><div><a target="_blank" href="http://www.tv3.ie/videos.php?video=46084&amp;locID=1.65.74">http://www.tv3.ie/videos.php?video=46084&amp;locID=1.65.74</a>  <br /></div><div><br /><div style="text-align:justify"><span style="color:#339999;font-size:x-large;text-align:justify">Speaking&nbsp;</span>We are available to speak at industry related conferences and can provide independent analysis as well as expert opinions for publishing or newspaper articles<span style="color:#000000;text-align:justify">.</span></div><div><br /></div><div style="text-align:justify"><br />Please contact our office on 01 8775460&nbsp;to discuss any of the above matters in detail.</div>  </div>', NULL, 3, 1, 1, '', 1),
(81, 59, 'products', 'Products', 'Products', 'Products', 'Products', '', '1', '40', NULL, NULL, NULL, '', NULL, '<div style="text-align:justify"><br /><span style="font-size:x-large;color:#339999">Motor dealers</span>&nbsp;can access our information via the following&nbsp;mediums.&nbsp;</div><div><span style="font-weight:bold;color:#3399ff"><br /></span></div><div><span style="font-weight:bold;font-size:large;color:#339999">A</span> the members area of this website</div><div><div><span style="font-weight:bold;font-size:large;color:#339999">B</span>&nbsp;our free&nbsp;iPhone app</div></div><div><span style="font-weight: bold; font-size: large; color: rgb(51, 153, 153); " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media1304103215225041" width="150" height="100">C</span> <span style="font-size:medium">o</span>ur long standing publications&nbsp;</div><div><span style="font-weight: bold; font-size: large; color: rgb(51, 153, 153); " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="" rel="media7653512335382402" width="150" height="100">D&nbsp;</span>our computer software</div><div><br /></div><div style="text-align:justify"> The software can be downloaded and instantly activated and our archived files can be used as refe<span style="font-size:medium">rence fo</span>r tracking a vehicle''s performance throughout the year. (sample screenshot of software)</div><div></div><div style="text-align:justify"><br /><span style="font-size:x-large;color:#339999">Insurance &amp; Finance Companies</span>&nbsp;should note that we provide a comprehensive solution to valuing vehicles for the purposes of underwriting and for the swift resolution of claims. The following video highlights how our values can be easily integrated into any existing system.&nbsp;</div><div><br /></div><div><iframe src="http://www.youtube.com/embed/qyg9t7RjOfM" frameborder="0" height="360" width="480"></iframe></div><span style="color:#339999;font-size:large;font-weight:bold"><br /></span><span style="color:#339999;font-size:x-large">Industry Reports</span> Our extensive research and analysis of the market ensures that we capture an unrivalled insight into the performance of the industry. This allows us to produce timely reports on a number of key market trends as well as shifts in consumer attitude and any other extraneous circumstances with a direct or indirect impact on the motor trade.  <br /><br /><div><span style="color: rgb(102, 102, 102); font-size: x-large; " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="http://qbix-soft.pl/mtp/assets/b406734b/images/pixel.gif" rel="media06931364862248302" width="150" height="100">&nbsp;</span><span style="color: rgb(102, 102, 102); font-size: x-large; " class="&lt;img src=" http:="" qbix-soft.pl="" mtp="" assets="" b406734b="" images="" pixel.gif"="" title="http://qbix-soft.pl/mtp/assets/b406734b/images/pixel.gif" rel="media5094425426796079" width="150" height="100"><iframe src="http://www.youtube.com/embed/aPQv5gxy5xo" frameborder="0" height="360" width="480"></iframe><br /></span></div><br /><span style="font-size:x-large;color:#339999">Expertise</span> Our prominence in the industry has attracted attention from radio programs such as TodayFM’s The Last Word with Matt Cooper and Q102’s The Scott Williams Show as well as having produced informative statistical analysis for use in newspaper articles. We also hope that our 13 page proposal for the restructuring of the motor tax system will form a critical role in the government’s overhaul of the framework for 2013. We appeared on Ireland AM to voice our standpoint on this in March 2012.&nbsp;<div><br /></div><div style="font-family:helvetica, sans-serif">The link to this interview can be found here:</div><div><br /></div><div><a href="http://www.tv3.ie/videos.php?video=46084&amp;locID=1.65.74">http://www.tv3.ie/videos.php?video=46084&amp;locID=1.65.74  </a><br /></div><div><br /><div style="text-align:justify"><span style="color:#339999;font-size:x-large;text-align:justify">Speaking&nbsp;</span>We are available to speak at industry related conferences and can provide independent analysis as well as expert opinions for publishing or newspaper articles<span style="color:#000000;text-align:justify">.</span></div><div><br /></div><div style="text-align:justify"><br />Please contact our office on 01 8775460&nbsp;to discuss any of the above matters in detail.</div>  </div>', NULL, 9, 1, 1, '', 1),
(60, 3, 'about', 'About', 'About', 'About', 'About', '', '1', '7', NULL, NULL, NULL, '', NULL, '<div style="text-align:justify;font-family:helvetica, sans-serif">Motor Trade Publishers, Ireland''s foremost authority in the field of valuing the widest range of used vehicles in the market, operate with the highest level of confidentiality and professionalism. For over 40 years our trade guides have provided scientific results for the&nbsp;<span style="font-style:italic">true selling&nbsp;</span>prices of vehicles. Our scope has reached in excess of 2,000&nbsp;individual models (and growing)&nbsp;whilst providing a support system for valuing models with any number of alternative levels of specification.</div><div style="text-align:justify"><br /><span style="font-family:helvetica, sans-serif">Values are constantly researched and examined for changes according to&nbsp;supply and demand,&nbsp;economic implications and&nbsp;seasonal impacts, as well as being cross checked against previous Guide values to ensure that a sensible value is always returned.</span>  </div><div style="text-align:justify"><br /></div><div style="text-align:justify;font-family:helvetica, sans-serif">We relish the opportunity to discuss our values with anyone and encourage all motor industry insiders to let us know their thoughts on the market.</div>', NULL, 7, 1, 1, '', 1),
