(74, 70, 'link_u', 'Reports', 'Link', 'Reports', 'Reports', 'Link', '1', '7', NULL, NULL, NULL, '', NULL, '<h2 style="font-family:helvetica, sans-serif;color:#339999"></h2><p style="font-family:helvetica, sans-serif;text-align:justify;font-size:medium">Conducting circa&nbsp;600 research visits nationwide equips us&nbsp;with an invaluable objective outlook on the industry.</p><p style="font-family:helvetica, sans-serif;text-align:justify;font-size:medium">The Reports page is for subscribers only and will feature regular updates concerning the performance of the motor industry.</p><p style="font-family:helvetica, sans-serif;text-align:justify;font-size:medium">Our keynote presentations, blog articles and webinars are designed to offer in-depth analysis of the market and afford subscribers with a greater degree of transparency concerning the manner in which we obtain values.</p><p style="font-family:helvetica, sans-serif;text-align:justify;font-size:medium">The Car Sales Guide values are not simply a process of establishing an average - our values come with their own stories.</p><p style="font-family:helvetica, sans-serif;font-size:large"><span style="color:#339999">27th March 2012</span>&nbsp;<span style="color:#339999">Top 3 two year old residuals per category (figures from February figures</span></p><p style="font-family:helvetica, sans-serif;font-size:large"><span style="color:#339999">*Change to MPV segment results to include Toyota Verso</span></p>\r\n<iframe width="480" height="360" src="http://www.youtube.com/embed/dbY9dYqHdxk" frameborder="0"></iframe><br /><div style="width:477px" id="__ss_12209848"><strong style="display:block;margin:12px 0 4px"><a href="http://www.slideshare.net/aidotimmo/official-motor-tax-report" title="Official Motor Tax Report">Official Motor Tax Report</a></strong></div> \r\n<div style="width:477px" id="__ss_12209848"> <strong style="display:block;margin:12px 0 4px"><a href="http://www.slideshare.net/aidotimmo/official-motor-tax-report" title="Official Motor Tax Report" target="_blank">Official Motor Tax Report</a></strong> <iframe src="http://www.slideshare.net/slideshow/embed_code/12209848" width="477" height="510" frameborder="0" marginwidth="0" marginheight="0" scrolling="no"></iframe><div style="padding:5px 0 12px"> View more <a href="http://www.slideshare.net/" target="_blank">documents</a> from <a href="http://www.slideshare.net/aidotimmo" target="_blank">aidotimmo</a> </div> </div>', NULL, 61, 1, 1, 'Link', 1),
(75, 63, 'login_welcome', 'login_welcome', 'login_welcome', 'Welcome ', 'login_welcome', '', '1', '7', NULL, NULL, NULL, '', NULL, '<p style="font-family:helvetica, sans-serif;text-align:justify">Thank You for using <span style="color:#339999;font-size:large">The Car Sales Guide </span>online</p><p style="font-family:helvetica, sans-serif;text-align:justify">The Car Sales Guide values are obtained from over 600\r\nresearch visits nationwide and values are updated every month.</p>\r\n<p style="font-family:helvetica, sans-serif;text-align:justify">Click on the <span style="font-size:large;color:#339999">Used Cars</span>&nbsp;tab at the top of the\r\nscreen and select which vehicle range you would like to search within.</p>\r\n<p style="font-family:helvetica, sans-serif;text-align:justify">If you have any queries concerning our values or if a\r\nvehicle does not appear in our listing, please use the feedback section at the\r\nbottom of the valuations page or click the <span style="color:#339999;font-size:large">Contact&nbsp;</span>tab in the top\r\nbanner.&nbsp;</p><span style="font-family:helvetica, sans-serif;text-align:justify">\r\nThank you for choosing to value your vehicle with The Car\r\nSales Guide – Ireland’s most accurate true selling valuation tool.</span><div><div style="text-align:justify"><span style="font-family:helvetica, sans-serif"><br /></span></div><div style="text-align:justify"><span style="font-family:helvetica, sans-serif">Incase you missed it, we have added the first of our industry measurements on the Reports page located under the Used Cars heading. Go check it out and let us know what you think.&nbsp;</span></div><span style="font-family:helvetica, sans-serif;text-align:justify"></span>  <div><span style="font-family:helvetica, sans-serif;text-align:justify"><br /></span></div><div><span style="font-family:helvetica, sans-serif;text-align:justify"><br /></span></div></div>', NULL, 6, 1, 1, '', 1),
(76, 63, 'licence_expired', 'license_expired', 'licence_expired', 'License Expired', 'license_expired', '', '1', '7', NULL, NULL, NULL, '', NULL, 'Your license has expired. This may be due to a number of reasons.<div><br /></div><div>1) Your trial period has ended. If you wish to continue using The Car Sales Guide online, please contact our office via the "Contact" tab at the top of the screen or call our office on 018775460</div><div><br /></div><div>2) Your annual subscription has expired. We authorize&nbsp;all users with&nbsp;an additional 30 days usage of our values&nbsp;to allow for payment to be arranged.</div><div><br /></div><div>If you feel as though neither of these circumstances relate to your account, please contact our office on 018775460</div><div><br /></div>', NULL, 7, 1, 1, '', 1),
