INSERT INTO `pl_cms_news` (`id`, `title`, `order`, `display`, `archive`, `txt`, `short_txt`, `_date`, `image`, `folder`) VALUES
(96, 'New updates for our iPhone app', 8, 1, 1, 'Get even more accurate values for your exact vehicle with our new kilometres adjustment calculator. We’re taking the guessing out of readjusting values for vehicles with higher or lower than average odometer readings with this addition to our app. Visit the App Store and download the update to receive this great new feature.', 'Get even more accurate values for your exact vehicle with our new kilometres adjustment calculator. We’re taking the guessing out of readjusting values for vehicles with higher or lower than average odometer readings with this addition to our app. Visit the App Store and download the update to receive this great new feature.', '2011-01-31', '1328894002.jpeg', '96'),
(102, 'Coming Soon', 6, 1, 1, 'We will launch our much loved “theCarguide” app for Android devices soon. It will feature all of what is currently available on our iPhone version. Users will now be able to take our values with them everywhere they go.', 'We will launch our much loved “theCarguide” app for Android devices soon. It will feature all of what is currently available on our iPhone version. Users will now be able to take our values with them everywhere they go.', '2012-01-01', '1329169311.jpeg', '102');
INSERT INTO `pl_cms_page` (`id`, `parent_id`, `url`, `name`, `title`, `header`, `link_name`, `keywords`, `function`, `layout`, `template`, `seo_visible`, `seo_unvisible`, `param_1`, `param_2`, `txt`, `button`, `order`, `editable`, `display`, `description`, `deletable`) VALUES
(3, 1, 'menu_top', '-- Menu top --', '-- Menu top --', 'menu_top', 'Menu gorne', 'menu_top', '1', 'layout_1', '', '', '', '', '', 'menu_top tresc strony layout none', '', 35, 1, 1, '', 0),
(1, 0, 'main', 'x-- Main --x', '-- Main --', 'main', 'main', 'main', '1', 'none', '', '', '', '', '', 'main', '', 36, 1, 1, NULL, 0),
(4, 3, 'home', 'Home', 'Home', 'Home', 'Home', 'Home', '3', '39', NULL, NULL, NULL, '', '102', '<span style="font-weight:bold">What you need to know....</span><br /><br />No one researches the used car market as comprehensively as us. Since 1967 Motor Trade Publishers has provided the motor industry with an essential tool for pricing the country’s most popular used vehicles. Since our research comes from the dealers themselves, the values’ accuracy can be relied upon. &nbsp;Don’t settle for guesses obtained from screening online asking prices. When it comes to valuing the retail price of used cars and maximizing your profits, make sure The Car Sales Guide and The Light Commercial &amp; Four Wheel Drive Guide are part of your arsenal.<br /><br />But don’t just take our word for it;<br /><br />“XXXXXX” – Joe Bloggs, Sales Manager Joe Bloggs, Toyota and Mercedes Main Dealer<br /><br />“YYYYYY” – Joe Bloggs, Owner of Joe Bloggs Motors, Ford Main Dealer<br /><br />Motor dealers, finance companies, insurance companies, Revenue, auctioneers, distributors and trade buyers and sellers – our clients know where to go for accurate used vehicle values and they’ve been coming to us for over 40 years.', NULL, 5, 1, 1, 'Home', 0),
(47, 3, 'contact', 'Contact', 'Contact', 'Contact', 'Contact', 'Contact', '2', '17', NULL, NULL, NULL, '', NULL, 'Contact', NULL, 17, 1, 1, 'Contact', 1),
(63, 1, 'misceleanous', 'misceleanous', 'misceleanous', 'misceleanous', 'misceleanous', '', '1', '7', NULL, NULL, NULL, '', NULL, 'misceleanous', NULL, 37, 1, 1, '', 1),
(64, 63, 'having_trouble_logging_in', 'Having trouble logging in?', 'Having trouble logging in?', 'Having trouble logging in?', 'Having trouble logging in?', '', '1', '7', NULL, NULL, NULL, '', NULL, '<form method="post">\r\n                        Having trouble logging in?<br /><br />Please contact us at <a href="mailto:info@mtp.ie">info@mtp.ie</a>  <br /></form>', NULL, 1, 1, 1, '', 1),
(42, 3, 'strona_z_menu', 'Mobile app', 'Strona z menu', 'Mobile app', 'Mobile app', 'Strona z menu', '1', '40', NULL, NULL, NULL, '', '21', 'Accurate used values at your fingertips….anywhere, anytime.<br /><br />Whether it’s from behind the desk, in a sales meeting, with a customer or simply to satisfy curiosity, theCarGuide app for iPhone allows subscribers to access our accurate data anywhere and anytime – FOR FREE.<br /><br />Easy to use – simple scroll and select functions. Makes and models are listed as they appear on distributor price lists so you don’t have to waste time inserting each vehicles individual detail. A sample screenshot to accompany this – I WILL SEND THIS TO YOU<br /><br />Kilometre adjustment calculator – select the relevant year and change the odometer reading to suit your particular model. Let our sophisticated kms adjustment algorithm return you an even more accurate value.<br /><br />Additional Notes – Our “info” icon at the top of the screen provides you with the technical details of your selected vehicle. Find out it’s CO2 value, engine cc, when the model was introduced or received a mid-model face lift as well as optional extras available and their price when new. A sample screenshot to accompany this. – I WILL SEND THIS TO YOU<br /><br />Time saving - Get the values that matter instantly without wasting time browsing pages of similar vehicles for sale and having to eliminate private sale values, asking prices or different body shapes. <br />Simply scroll, select and sell.', NULL, 6, 1, 1, 'Strona z menu', 1),
(48, 42, 'pod_strona_b', 'Pod strona B', 'Pod strona B', 'Pod strona B', 'Pod strona B', 'Pod strona B', '1', '7', NULL, NULL, NULL, '', NULL, 'Pod strona B', NULL, 15, 1, 1, 'Pod strona B', 1),
(59, 3, 'services', 'Services', 'Services', 'Services', 'Services', '', '1', '40', NULL, NULL, NULL, '', '96', 'Motor dealers can access our information via a number of mediums including a). the members area of this website; b). their iPhone; c). our long standing publications and d). our computer software. The software can be downloaded and instantly activated and our archived files can be used as reference for tracking a vehicles performance throughout the year. (sample screenshot of software)<br /> <br />Corporate clients have the same options as well as the ability to assimilate our raw data file into any type of system.<br />Finance companies can dramatically reduce their risk when underwriting vehicles as our values are constantly updated from our extensive nationwide research.<br />Insurance companies may wish to avail of our raw data files too to help with setting premiums or in the event of vehicle write-offs. Both underwriting and claims departments benefit from our information by taking the responsibility of setting a value at a policy’s inception away from the customer and placing it with a company who know the market best.<br />***<br />Advertising: Attractive rates targeting a significant majority of the motor trade helps to ease the financial burden facing companies nowadays. <br />***<br />Vehicle Valuations: [Blurb here on this service with a link to our old vehicle valuations page which will be done up in a future phase.]<br />***<br />Industry Reports: Our extensive research and analysis of the market ensures that we capture an unrivalled insight into the performance of the industry. This allows us to produce timely reports on a number of key market trends as well as shifts in consumer attitude and any other extraneous circumstances with a direct or indirect impact on the motor trade.<br />***<br />Expertise: Our prominence in the industry has attracted attention from radio programs such as TodayFM’s The Last Word with Matt Cooper and Q102’s The Scott Williams Show as well as having produced informative statistical analysis for use in newspaper articles. We also hope that our 13 page proposal for the restructuring of the motor tax system will form a critical role in the government’s overhaul of the framework for 2013.<br />***<br />Please contact our office to discuss any of the above matters in detail.', NULL, 7, 1, 1, '', 1),
(60, 3, 'about', 'About', 'About', 'About', 'About', '', '1', '7', NULL, NULL, NULL, '', NULL, 'Motor Trade Publishers, Ireland''s foremost authority in the field of valuing the widest range of used vehicles in the market, operate with the highest level of confidentiality and professionalism. For over 40 years our trade guides have provided scientific results for the logical selling prices of vehicles. Our scope has reached in excess of 2,000 individual models whilst providing a support system for valuing models with any number of alternative levels of specification.<br /><br />Values are constantly researched and examined for changes due to: a). supply and demand, b). economic implications and c). seasonal impacts, as well as being cross checked against previous Guide values to ensure that a sensible value is always returned.', NULL, 8, 1, 1, '', 1),
(62, 42, 'app', 'App', 'App', 'app', 'App', '', '1', '7', NULL, NULL, NULL, '', NULL, '', NULL, 3, 1, 1, '', 1);
